-- ملء محتوى عنقود "المناسبات الإسلامية" (munasabat-islamiyya) — ستة
-- تصنيفات فرعية draft بالكامل: رمضان وليلة القدر والعشر
-- (ramadan-laylat-qadr)، العيدان (idan)، الحج وعشر ذي الحجة وعرفة
-- (hajj-ashr-dhul-hijja)، المحرم وعاشوراء (muharram-ashura)، الجمعة
-- وأحكام الأهلة (jumua)، مناسبات لا أصل لها (munasabat-la-asl). كل
-- تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بأسلوب الدفعات السابقة (body + examples).
-- المصادر المعتمدة المسمّاة صراحة لكل درس، تحقَّقت عبر WebSearch/WebFetch
-- من نصها الرسمي مباشرة قبل الصياغة (كلها فتاوى دار الإفتاء المصرية):
-- 1) رمضان وليلة القدر: فتوى رقم 4458 (معنى ليلة القدر، 28-11-2002م،
--    أ.د/ أحمد الطيب).
-- 2) العيدان: فتوى رقم 7553 (كيفية أداء صلاة العيد، 29-8-2011م، أ.د/
--    علي جمعة).
-- 3) الحج وعشر ذي الحجة: فتوى رقم 8009 (مدى ورود شيء مخصوص في صيام
--    أيام العشر من ذي الحجة ومشروعية ذلك، 26-9-2023م، أ.د/ شوقي
--    إبراهيم علام).
-- 4) المحرم وعاشوراء: فتوى رقم 8669 (حكم صيام يوم عاشوراء وإفراده
--    بالصيام، 25-6-2025م، أ.د/ نظير محمد عياد).
-- 5) الجمعة: فتوى رقم 7351 (فضل يوم الجمعة والأعمال المستحبة فيه،
--    31-3-2014م، أ.د/ شوقي إبراهيم علام).
-- 6) مناسبات لا أصل لها: فتوى رقم 8839 (حكم صلاة الرغائب في شهر رجب،
--    30-12-2025م، أ.د/ نظير محمد عياد) — اختير مثالاً محددًا وموثَّقًا
--    (صلاة الرغائب) بدل تعميم غير دقيق، لأن دار الإفتاء نفسها تجيز عدة
--    مناسبات أخرى قد يُظن للوهلة الأولى أنها بلا أصل (كالإسراء والمعراج
--    والنصف من شعبان)، فتحقَّق أولاً عبر WebSearch من موقفها الفعلي في
--    كل مناسبة قبل الاختيار، ووقع الاختيار على صلاة الرغائب لكونها
--    المثال الذي صرّحت فيه دار الإفتاء نفسها بالوضع وشدة الضعف.
-- ست آيات تحقَّقت حرفياً محليًا من artifacts/majalis/public/data/quran
-- عبر numberInSurah: القدر 3، البقرة 185، الحج 28، إبراهيم 5، الجمعة
-- 9، الشورى 21. ستة أحاديث تحقَّقت عبر WebSearch من نصها وتخريجها
-- ودرجتها بدقة: دعاء ليلة القدر "اللهم إنك عفو تحب العفو فاعف عني"
-- (الترمذي 3513 حسن صحيح، صححه الألباني والأرناؤوط)، حديث ابن عباس في
-- صفة صلاة العيد ركعتين (متفق عليه، البخاري 989 ومسلم 884)، حديث ابن
-- عباس "ما من أيام العمل الصالح فيهن أحب إلى الله من هذه الأيام
-- العشر" (البخاري 969)، حديث ابن عباس في صيام النبي لعاشوراء شكرًا
-- لنجاة موسى (متفق عليه، البخاري 2004 ومسلم 1130)، حديث أبي هريرة
-- "خير يوم طلعت عليه الشمس يوم الجمعة" (مسلم 854)، وحديث عائشة "من
-- أحدث في أمرنا هذا ما ليس منه فهو رد" (متفق عليه، البخاري 2697 ومسلم
-- 1718). idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم
-- status='published' للتصنيفات الستة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) رمضان وليلة القدر والعشر
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='196b587c-8fb3-40d7-b846-d38f1b944d7c' AND title='فضل ليلة القدر ومعناها وعلاماتها الصحيحة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فضل ليلة القدر ومعناها وعلاماتها الصحيحة', 'بيان معنى ليلة القدر وفضلها العظيم والفهم الصحيح لعلاماتها كما جاء في فتوى دار الإفتاء المصرية رقم 4458', '196b587c-8fb3-40d7-b846-d38f1b944d7c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'ليلة القدر ليلة مغفرة وقَبول لا ظاهرة حسية تُنتظر', 'بيّنت الفتوى أن ليلة القدر هي ليلة المغفرة وقبول الأعمال والعتق من النار، وأن الله تعالى وصف العبادة فيها بأنها خير من عبادة ألف شهر، أي أكثر من ثلاث وثمانين سنة، تفضلاً منه على هذه الأمة بتعويضها عمّا قد يفوتها من طول العمر بقصر الزمن وعظم الأجر. وفي هذه الليلة المباركة تتنزل الملائكة إلى الأرض فتسلّم على المؤمنين الصائمين القائمين وتستغفر لهم إلى مطلع الفجر. وأخفى الله تعالى تعيين موعدها بين ليالي العشر الأواخر من رمضان حكمةً منه، ليجتهد المسلم في طلبها في جميع لياليها لا في ليلة بعينها، فتزداد عبادته ورجاؤه. وحذّرت الفتوى من تصور بعض الناس أنها ظاهرة حسية مرئية تُشاهد بالعين، مبينةً أن المقصود منها هو الاجتهاد في الصلاة والاستغفار وتلاوة القرآن، إذ يقبل الله فيها من الأعمال ما لا يقبله في سواها.', 1),
    (v_lesson, 'examples', 'آية خيريتها على ألف شهر ودعاء النبي المعلَّم لعائشة فيها', 'قال تعالى: ﴿لَيْلَةُ الْقَدْرِ خَيْرٌ مِّنْ أَلْفِ شَهْرٍ﴾ (القدر: 3)، وهي الآية التي بيّنت الفضل العظيم لهذه الليلة، إذ فاق العمل الصالح فيها ثواب العمل في أكثر من ثلاثة وثمانين عامًا خلت منها. وفي بيان ما يُشرع للمسلم أن يدعو به فيها تحديدًا، عن عائشة رضي الله عنها قالت: قلت: يا رسول الله، أرأيت إن علمت أي ليلة ليلة القدر ما أقول فيها؟ قال: "قولي: اللهم إنك عفو تحب العفو فاعف عني" (رواه الترمذي 3513 وأحمد وابن ماجه، وقال الترمذي: حديث حسن صحيح، وصححه الألباني وشعيب الأرناؤوط). فهذا الحديث يبيّن أن أولى ما يشتغل به المسلم في هذه الليلة العظيمة سؤال العفو، لأنها ليلة مغفرة وقبول لا مجرد ليلة عبادة عابرة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 4458: معنى ليلة القدر (28 نوفمبر 2002م، أ.د/ أحمد الطيب)', 1);
  END IF;

  -- 2) العيدان
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='57c85462-d104-43d5-a3a7-78cf07a69d9a' AND title='أحكام صلاة العيد وآدابها المستحبة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أحكام صلاة العيد وآدابها المستحبة', 'بيان حكم صلاة العيد ووقتها وصفتها وآدابها المستحبة كما جاء في فتوى دار الإفتاء المصرية رقم 7553', '57c85462-d104-43d5-a3a7-78cf07a69d9a', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'صلاة العيد سنة مؤكدة بصفة محددة وآداب مستحبة قبلها', 'بيّنت الفتوى أن صلاة العيد سنة مؤكدة واظب عليها النبي صلى الله عليه وسلم، وأمر بحضورها الرجال والنساء حتى ذوات الأعذار منهن ليشهدن الخير ودعوة المسلمين. ويبدأ وقتها من ارتفاع الشمس قدر رمح ويمتد إلى ابتداء الزوال عند جمهور الفقهاء. وصفتها ركعتان يُكبَّر في الأولى سبع تكبيرات سوى تكبيرة الإحرام، وفي الثانية خمس تكبيرات سوى تكبيرة القيام، ترفع فيها اليدان عند كل تكبيرة، ويُستحب الوقوف بين كل تكبيرتين بقدر آية للتسبيح والتهليل، ثم تُقرأ الفاتحة وسورة كسورتي الأعلى والغاشية جهرًا. وبعد الفراغ من الصلاة يخطب الإمام خطبتين يفصل بينهما بجلسة، مستفتحًا الأولى بتسع تكبيرات والثانية بسبع. ومن الآداب المستحبة قبل الخروج إليها الاغتسال ولبس أفضل الثياب.', 1),
    (v_lesson, 'examples', 'آية التكبير بعد إكمال العدة وحديث اقتصار صلاة العيد على ركعتين', 'قال تعالى: ﴿... وَلِتُكْمِلُوا الْعِدَّةَ وَلِتُكَبِّرُوا اللَّهَ عَلَىٰ مَا هَدَاكُمْ وَلَعَلَّكُمْ تَشْكُرُونَ﴾ (البقرة: 185)، وهي ختام آية فرض الصيام، وفيها الأصل القرآني لمشروعية التكبير عند إكمال عدة رمضان، وهو ما تحقق مظهره الأظهر في تكبيرات عيد الفطر وصلاته شكرًا لله على نعمة الهداية والتيسير. وفي بيان صفة صلاة العيد وعدد ركعاتها، عن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم صلى العيد ركعتين لم يصل قبلهما ولا بعدهما (متفق عليه، رواه البخاري 989 ومسلم 884). فهذا الحديث يبيّن أن صلاة العيد مقصورة على ركعتين فحسب دون نافلة قبلها أو بعدها في موضع أدائها، خلافًا لسائر الصلوات ذوات الرواتب.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 7553: كيفية أداء صلاة العيد (29 أغسطس 2011م، أ.د/ علي جمعة)', 1);
  END IF;

  -- 3) الحج وعشر ذي الحجة وعرفة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='5ac5851d-4878-4d1b-8427-739a7f9fc49e' AND title='فضل صيام عشر ذي الحجة ويوم عرفة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فضل صيام عشر ذي الحجة ويوم عرفة', 'بيان استحباب صيام العشر الأول من ذي الحجة وتأكده في يوم عرفة كما جاء في فتوى دار الإفتاء المصرية رقم 8009', '5ac5851d-4878-4d1b-8427-739a7f9fc49e', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'صيام العشر الأول من ذي الحجة مستحب ويتأكد في يوم عرفة', 'بيّنت الفتوى أن صيام العشر الأول من ذي الحجة (من أول الشهر إلى التاسع) من أجلّ المستحبات وأعظم القربات، وقد وردت في فضله نصوص عامة وخاصة أطبق عليها الفقهاء من جميع المذاهب. ويتأكد استحباب صيامه في اليوم التاسع خاصة، وهو يوم عرفة، لورود نص خاص في عظيم فضله لغير الحاج. أما اليوم العاشر من ذي الحجة فهو يوم عيد الأضحى، وصيامه محرم بإجماع الفقهاء. وأشارت الفتوى إلى ما استُشكل من حديث عائشة الذي نفت فيه رؤيتها للنبي صائمًا هذه الأيام، مبينة أن هذا النفي محمول على عدم رؤيتها الفعلية له لعارض كسفر أو مرض، وأن النصوص المثبتة للفضل مقدمة على ما ظاهره النفي، لأن مثبت الفضل عنده علم زائد على النافي.', 1),
    (v_lesson, 'examples', 'آية الأيام المعلومات وحديث أفضلية العمل الصالح في العشر', 'قال تعالى: ﴿لِّيَشْهَدُوا مَنَافِعَ لَهُمْ وَيَذْكُرُوا اسْمَ اللَّهِ فِي أَيَّامٍ مَّعْلُومَاتٍ عَلَىٰ مَا رَزَقَهُم مِّن بَهِيمَةِ الْأَنْعَامِ﴾ (الحج: 28)، وقد فسّر ابن عباس وابن عمر رضي الله عنهم "الأيام المعلومات" في هذه الآية بأنها العشر الأول من ذي الحجة، فهي الأصل القرآني الذي تُبنى عليه عظمة هذه الأيام. وفي بيان مفاضلة العمل الصالح فيها على ما سواه من الأزمنة، عن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم قال: "ما من أيام العمل الصالح فيهن أحب إلى الله من هذه الأيام العشر"، قالوا: يا رسول الله، ولا الجهاد في سبيل الله؟ قال: "ولا الجهاد في سبيل الله، إلا رجل خرج بنفسه وماله فلم يرجع من ذلك بشيء" (رواه البخاري 969). فهذا الحديث يبيّن أن هذه الأيام العشر تفضل حتى الجهاد المعتاد في الأجر، لما اجتمع فيها من أنواع العبادات التي لا تجتمع في غيرها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 8009: مدى ورود شيء مخصوص في صيام أيام العشر من ذي الحجة ومشروعية ذلك (26 سبتمبر 2023م، أ.د/ شوقي إبراهيم علام)', 1);
  END IF;

  -- 4) المحرم وعاشوراء
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='15ed53e0-afd7-46c6-b3a9-f1145ae91844' AND title='فضل صيام يوم عاشوراء وحكم إفراده بالصيام') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فضل صيام يوم عاشوراء وحكم إفراده بالصيام', 'بيان فضل صيام يوم عاشوراء وحكم إفراده دون التاسع أو الحادي عشر كما جاء في فتوى دار الإفتاء المصرية رقم 8669', '15ed53e0-afd7-46c6-b3a9-f1145ae91844', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'صيام عاشوراء مستحب مكفّر وإفراده بالصيام جائز بلا كراهة', 'بيّنت الفتوى أن صيام يوم عاشوراء، وهو العاشر من شهر الله المحرم، أمر مستحب شرعًا ثابت عن النبي صلى الله عليه وسلم بالسنة الفعلية والقولية، وأن من صامه يُثاب بتكفير ذنوب سنة كاملة قبله. وبيّنت أن الأفضل والأكمل هو الجمع في الصيام بين ثلاثة أيام: التاسع والعاشر والحادي عشر من المحرم، تطبيقًا لتوجيه النبي صلى الله عليه وسلم حين عزم على صيام التاسع مخالفة لليهود. أما إن اختار المسلم إفراد اليوم العاشر وحده بالصيام دون التاسع أو الحادي عشر، فذلك جائز شرعًا من غير كراهة، سواء كان ذلك بعذر منعه من صيام يوم آخر معه أو بغير عذر، وليس عليه في ذلك إثم ولا حرج.', 1),
    (v_lesson, 'examples', 'التذكير بأيام الله وحديث صيام النبي عاشوراء شكرًا لنجاة موسى', 'قال تعالى: ﴿وَلَقَدْ أَرْسَلْنَا مُوسَىٰ بِآيَاتِنَا أَنْ أَخْرِجْ قَوْمَكَ مِنَ الظُّلُمَاتِ إِلَى النُّورِ وَذَكِّرْهُم بِأَيَّامِ اللَّهِ﴾ (إبراهيم: 5)، وفيها أصل عام في مشروعية تذكير الناس بأيام الله التي أظهر فيها نصر أوليائه وأنجاهم من أعدائهم، ومنها ما وقع لموسى عليه السلام يوم عاشوراء. وفي بيان سبب صيام النبي صلى الله عليه وسلم لهذا اليوم تحديدًا، عن ابن عباس رضي الله عنهما: أن النبي صلى الله عليه وسلم قدم المدينة فرأى اليهود تصوم يوم عاشوراء، فقال: "ما هذا؟"، قالوا: هذا يوم صالح، هذا يوم نجى الله فيه بني إسرائيل من عدوهم فصامه موسى، قال: "فأنا أحق بموسى منكم"، فصامه وأمر بصيامه (متفق عليه، رواه البخاري 2004 ومسلم 1130). فهذا الحديث يبيّن أن صيام عاشوراء شكر لله على نجاة نبيه موسى عليه السلام، وأن هذه الأمة أولى بهذا الشكر ممن سبقها إليه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 8669: حكم صيام يوم عاشوراء وإفراده بالصيام (25 يونيو 2025م، أ.د/ نظير محمد عياد)', 1);
  END IF;

  -- 5) الجمعة وأحكام الأهلة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='8620c8f8-2cef-4f71-89f6-968e1e71b0f1' AND title='فضل يوم الجمعة والأعمال المستحبة فيه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فضل يوم الجمعة والأعمال المستحبة فيه', 'بيان فضل يوم الجمعة وخصوصيته لهذه الأمة والأعمال المستحبة فيه كما جاء في فتوى دار الإفتاء المصرية رقم 7351', '8620c8f8-2cef-4f71-89f6-968e1e71b0f1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الجمعة عيد أسبوعي مختص بهذه الأمة وله أعمال مستحبة', 'بيّنت الفتوى أن يوم الجمعة يتمتع بمكانة خاصة في الإسلام، إذ اختصت به هذه الأمة المحمدية دون الأمم السابقة التي ضلّت عنه، فكان لليهود السبت وللنصارى الأحد، وهو عيد للمسلمين وأفضل أيام الأسبوع وخير يوم طلعت عليه الشمس، فيه خُلق آدم عليه السلام وفيه أُدخل الجنة وفيه أُخرج منها. ومن فضائله أن الصلوات الخمس والجمعة إلى الجمعة كفارة لما بينهما ما اجتُنبت الكبائر، وفيه ساعة لا يُرد فيها دعاء داعٍ. وذكرت الفتوى جملة من الأعمال المستحبة في هذا اليوم: الاغتسال، ولبس أحسن الثياب والأبيض أفضلها، والتعطر، والتبكير إلى صلاة الجمعة إذ يُضاعف الأجر بالتبكير، مع الإكثار من الصلاة على النبي وقراءة سورة الكهف والتماس ساعة الإجابة فيه.', 1),
    (v_lesson, 'examples', 'آية السعي إلى ذكر الله وحديث خيرية يوم الجمعة', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا نُودِيَ لِلصَّلَاةِ مِن يَوْمِ الْجُمُعَةِ فَاسْعَوْا إِلَىٰ ذِكْرِ اللَّهِ وَذَرُوا الْبَيْعَ ذَٰلِكُمْ خَيْرٌ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ﴾ (الجمعة: 9)، وهي الآية التي أوجبت السعي إلى صلاة الجمعة وترك البيع عند ندائها، تقديمًا لذكر الله على منافع الدنيا. وفي بيان عظم منزلة هذا اليوم على سائر أيام الأسبوع، عن أبي هريرة رضي الله عنه أن النبي صلى الله عليه وسلم قال: "خير يوم طلعت عليه الشمس يوم الجمعة، فيه خُلق آدم، وفيه أُدخل الجنة، وفيه أُخرج منها، ولا تقوم الساعة إلا في يوم الجمعة" (رواه مسلم 854). فهذا الحديث يبيّن أن الجمعة يوم جامع لأعظم أحداث الخلق والمصير، مما يوجب على المسلم تعظيمه واغتنام ما فيه من فضل.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 7351: فضل يوم الجمعة والأعمال المستحبة فيه (31 مارس 2014م، أ.د/ شوقي إبراهيم علام)', 1);
  END IF;

  -- 6) مناسبات لا أصل لها
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='6d0d2266-5d48-40c6-b8aa-3bc060de7e4b' AND title='حكم صلاة الرغائب: نموذج لمناسبة لا أصل لها في الدين') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حكم صلاة الرغائب: نموذج لمناسبة لا أصل لها في الدين', 'بيان حكم صلاة الرغائب المخصوصة في رجب وبيان أنها بدعة لا أصل لها كما جاء في فتوى دار الإفتاء المصرية رقم 8839', '6d0d2266-5d48-40c6-b8aa-3bc060de7e4b', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'صلاة الرغائب نموذج لعبادة مخصوصة لم يثبت لها أصل صحيح', 'بيّنت الفتوى أن ما يُعرف بـ"صلاة الرغائب"، وهي صلاة اثنتا عشرة ركعة تؤدى بصفة مخصوصة بين المغرب والعشاء ليلة أول جمعة من شهر رجب بعد صيام الخميس السابق لها، لم يثبت بحديث صحيح عن النبي صلى الله عليه وسلم بهذه الكيفية المعروفة، ولم يُنقل فعلها عن الصحابة ولا التابعين. وأوضحت أن الحديث الوارد في بيان فضلها حكم عليه حفاظ الحديث كابن الجوزي والعراقي والعجلوني بالوضع والضعف الشديد. وبيّنت أن وجه الإنكار على هذه الصلاة إنما ينصبّ على نسبتها إلى النبي صلى الله عليه وسلم بصفة مخصوصة من عدد ركعات وهيئة معينة من غير دليل صحيح، لا على أصل التنفل بين المغرب والعشاء، فباب النوافل مفتوح لمن أراد التطوع في هذا الوقت من غير التزام بعدد أو كيفية محددة.', 1),
    (v_lesson, 'examples', 'آية التشريع بغير إذن الله وحديث رد كل محدثة في الدين', 'قال تعالى: ﴿أَمْ لَهُمْ شُرَكَاءُ شَرَعُوا لَهُم مِّنَ الدِّينِ مَا لَمْ يَأْذَن بِهِ اللَّهُ﴾ (الشورى: 21)، وهي أصل قرآني في إنكار كل عبادة أو تشريع دخل في الدين دون إذن من الله ورسوله، وهو المعنى الذي تندرج تحته العبادات المخصوصة التي لا يشهد لها دليل صحيح. وفي بيان الميزان العام الذي يُعرف به مقبول الأعمال من مردودها، عن عائشة رضي الله عنها أن النبي صلى الله عليه وسلم قال: "من أحدث في أمرنا هذا ما ليس منه فهو رد" (متفق عليه، رواه البخاري 2697 ومسلم 1718). فهذا الحديث هو الأصل الذي بنت عليه دار الإفتاء حكمها ببطلان نسبة صلاة الرغائب بصفتها المخصوصة إلى الشرع، لأنها محدثة لم يأذن بها الله ولا رسوله.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'fatwa_body', 'دار الإفتاء المصرية، فتوى رقم 8839: حكم صلاة الرغائب في شهر رجب (30 ديسمبر 2025م، أ.د/ نظير محمد عياد)', 1);
  END IF;

